import 'dart:convert';
import 'package:task_manager_flutter/data/models/role_model.dart'; // Ajuste o caminho conforme necessário
import 'package:task_manager_flutter/data/utils/api_links.dart'; // Onde definiremos as URLs
import 'package:task_manager_flutter/data/models/network_response.dart';
import 'package:task_manager_flutter/data/services/network_caller.dart';

class RoleCaller {
  Future<List<Role>> getRoles() async {
    List<Role> rolesList = [];
    try {
      final NetworkResponse response =
          await NetworkCaller().getRequest(ApiLinks.getAllRoles);

      if (response.statusCode == 200 && response.body != null) {
        // A resposta é um mapa, e esperamos que tenha uma chave 'data' que é um mapa com 'content' (lista de roles)
        final Map<String, dynamic> responseData = response.body!;
        if (responseData.containsKey('data')) {
          final List<dynamic> rolesJson = responseData['data']['content'];
          rolesList = rolesJson.map((json) => Role.fromJson(json)).toList();
        } else {
          throw Exception('Estrutura de resposta inválida: falta a chave "data"');
        }
      } else {
        throw Exception('Falha ao carregar roles: ${response.statusCode}');
      }
    } catch (e) {
      print('Erro: $e');
      throw Exception('Erro ao carregar roles: $e');
    }
    return rolesList;
  }

  Future<bool> associateRoleToLogin(int loginId, int roleId) async {
    try {
      final NetworkResponse response = await NetworkCaller().postRequest(
        ApiLinks.associateRoleToLogin(loginId, roleId),
        // Como é uma associação, não enviamos body, mas se a API exigir, ajuste aqui.
        // No exemplo, o endpoint é POST e não tem body.
      );

      if (response.statusCode == 200) {
        return true;
      } else {
        return false;
      }
    } catch (e) {
      print('Erro: $e');
      return false;
    }
  }

  Future<bool> removeRoleFromLogin(int loginId, int roleId) async {
    try {
      final NetworkResponse response = await NetworkCaller().deleteRequest(
        ApiLinks.removeRoleFromLogin(loginId, roleId),
      );

      if (response.statusCode == 204) {
        return true;
      } else {
        return false;
      }
    } catch (e) {
      print('Erro: $e');
      return false;
    }
  }
}
